(function() {
  const ctx = document.getElementById('paretoChart').getContext('2d');

  // Data from Figure 1 — average accuracy across 5 benchmarks vs log10(avg FLOPs)
  // Dense models (blue), MoE models (yellow/orange)
  const denseModels = [
    { label: 'Gemma-3-1B', x: 13.0, y: 0.255, r: 4 },
    { label: 'Gemma-3-4B', x: 13.6, y: 0.393, r: 6 },
    { label: 'Gemma-3n-E2B', x: 13.8, y: 0.342, r: 5 },
    { label: 'Gemma-3n-E4B', x: 14.1, y: 0.412, r: 6 },
    { label: 'Gemma-3-12B', x: 14.5, y: 0.479, r: 8 },
    { label: 'Phi-4', x: 14.4, y: 0.510, r: 9 },
    { label: 'Gemma-3-27B', x: 15.0, y: 0.537, r: 11 },
    { label: 'Phi-4-Mini', x: 15.2, y: 0.564, r: 7 },
    { label: 'Phi-4-Plus', x: 15.6, y: 0.663, r: 10 },
    { label: 'Llama-3.1-8B', x: 15.4, y: 0.329, r: 7 },
    { label: 'DeepSeek-R1-Qwen3-8B', x: 15.5, y: 0.635, r: 7 },
    { label: 'Nemotron-Nano-9B-v2', x: 15.6, y: 0.656, r: 8 },
    { label: 'Qwen3-4B Instruct', x: 14.8, y: 0.641, r: 6 },
    { label: 'Qwen3-4B Thinking', x: 15.3, y: 0.770, r: 6 }
  ];

  const moeModels = [
    { label: 'GPT-OSS-20B Low', x: 13.8, y: 0.604, r: 9 },
    { label: 'GPT-OSS-20B Med', x: 15.0, y: 0.741, r: 9 },
    { label: 'GPT-OSS-20B High', x: 16.0, y: 0.803, r: 9 },
    { label: 'Qwen3-30B-A3B Instruct', x: 15.2, y: 0.700, r: 11 },
    { label: 'Qwen3-30B-A3B Thinking', x: 15.5, y: 0.838, r: 11 }
  ];

  new Chart(ctx, {
    type: 'bubble',
    data: {
      datasets: [
        {
          label: 'Dense',
          data: denseModels.map(m => ({ x: m.x, y: m.y * 100, r: m.r })),
          backgroundColor: 'rgba(77, 171, 247, 0.55)',
          borderColor: '#4dabf7',
          borderWidth: 1.5
        },
        {
          label: 'MoE',
          data: moeModels.map(m => ({ x: m.x, y: m.y * 100, r: m.r })),
          backgroundColor: 'rgba(246, 173, 85, 0.6)',
          borderColor: '#f6ad55',
          borderWidth: 1.5
        }
      ]
    },
    options: {
      animation: false,
      maintainAspectRatio: false,
      scales: {
        x: {
          title: {
            display: true,
            text: 'log₁₀(Average FLOPs per query)',
            font: { size: 12, family: 'system-ui' },
            color: '#4a5568'
          },
          min: 12.5,
          max: 16.5,
          grid: { color: '#e2e8f0' },
          ticks: { color: '#718096', font: { size: 11 } }
        },
        y: {
          title: {
            display: true,
            text: 'Average Accuracy (%)',
            font: { size: 12, family: 'system-ui' },
            color: '#4a5568'
          },
          min: 20,
          max: 95,
          grid: { color: '#e2e8f0' },
          ticks: {
            color: '#718096',
            font: { size: 11 },
            callback: function(v) { return v + '%'; }
          }
        }
      },
      plugins: {
        legend: {
          labels: {
            color: '#4a5568',
            font: { size: 12, family: 'system-ui' },
            usePointStyle: true,
            pointStyle: 'circle'
          }
        },
        tooltip: {
          callbacks: {
            label: function(context) {
              const ds = context.dataset.label;
              const allModels = ds === 'Dense' ? denseModels : moeModels;
              const m = allModels[context.dataIndex];
              return m ? m.label + ': ' + (m.y * 100).toFixed(1) + '% at 10^' + m.x.toFixed(1) + ' FLOPs' : '';
            }
          }
        }
      }
    }
  });
})();
